mapper.select:
SELECT h.*, MIN(rt.price) AS min_price, (SELECT ROUND(AVG(r.score), 1) FROM t_review r JOIN t_order o ON o.order_id = r.order_id WHERE o.hotel_id = h.hotel_id) AS avg_score FROM t_hotel h JOIN t_room_type rt ON rt.hotel_id = h.hotel_id
AND h.city = #{city} AND h.district = #{district} AND h.hotel_name LIKE CONCAT('%', #{name}, '%') AND rt.price >= #{priceMin} AND rt.price <= #{priceMax}
GROUP BY h.hotel_id ORDER BY h.star DESC, min_price
